package main

import (
    "fmt"
    "sync"
    "time"
)

// ---- Simulated file download ----
func downloadFile(id int, size int, wg *sync.WaitGroup, results chan<- string) {
    defer wg.Done()

    fmt.Printf("File %d: Starting download (%d MB)\n", id, size)

    // Simulate download time
    time.Sleep(time.Duration(size) * 100 * time.Millisecond)

    result := fmt.Sprintf("File %d: Downloaded %d MB", id, size)
    results <- result
    fmt.Printf("File %d: Done\n", id)
}

// ---- Concurrent download manager ----
func main() {
    fmt.Println("=== Concurrent File Downloader ===")

    // ---- File list ----
    files := []struct {
        ID   int
        Size int
    }{
        {1, 2},
        {2, 3},
        {3, 1},
        {4, 4},
        {5, 2},
    }

    // ---- Download all files ----
    var wg sync.WaitGroup
    results := make(chan string, len(files))

    start := time.Now()

    for _, file := range files {
        wg.Add(1)
        go downloadFile(file.ID, file.Size, &wg, results)
    }

    wg.Wait()
    close(results)

    elapsed := time.Since(start)

    // ---- Collect results ----
    fmt.Println("\n=== Results ===")
    for result := range results {
        fmt.Println(result)
    }

    fmt.Printf("\nTotal time: %v\n", elapsed)

    // ---- Download with concurrency limit ----
    fmt.Println("\n=== Download with Concurrency Limit ===")

    concurrencyLimit := 2
    semaphore := make(chan struct{}, concurrencyLimit)

    var wg2 sync.WaitGroup
    results2 := make(chan string, len(files))

    start2 := time.Now()

    for _, file := range files {
        wg2.Add(1)
        go func(f struct{ ID, Size int }) {
            defer wg2.Done()

            semaphore <- struct{}{} // Acquire
            defer func() { <-semaphore }() // Release

            downloadFile(f.ID, f.Size, &wg2, results2)
        }(file)
    }

    wg2.Wait()
    close(results2)

    elapsed2 := time.Since(start2)

    fmt.Println("\n=== Results (with limit) ===")
    for result := range results2 {
        fmt.Println(result)
    }

    fmt.Printf("\nTotal time (with limit): %v\n", elapsed2)

    // ---- Download with progress tracking ----
    fmt.Println("\n=== Download with Progress ===")

    var mu sync.Mutex
    completed := 0
    total := len(files)

    var wg3 sync.WaitGroup

    for _, file := range files {
        wg3.Add(1)
        go func(f struct{ ID, Size int }) {
            defer wg3.Done()

            time.Sleep(time.Duration(f.Size) * 50 * time.Millisecond)

            mu.Lock()
            completed++
            fmt.Printf("Progress: %d/%d files completed\n", completed, total)
            mu.Unlock()
        }(file)
    }

    wg3.Wait()
    fmt.Println("All files downloaded!")
}

